
CREATE TABLE public.programs (
  id text PRIMARY KEY,
  name text NOT NULL,
  description text NOT NULL DEFAULT '',
  icon text NOT NULL DEFAULT 'Building2',
  about text NOT NULL DEFAULT '',
  guidelines jsonb NOT NULL DEFAULT '[]'::jsonb,
  sort_order integer NOT NULL DEFAULT 0,
  created_at timestamptz NOT NULL DEFAULT now(),
  updated_at timestamptz NOT NULL DEFAULT now()
);

ALTER TABLE public.programs ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Anyone can read programs" ON public.programs FOR SELECT TO public USING (true);
CREATE POLICY "Authenticated can insert programs" ON public.programs FOR INSERT TO authenticated WITH CHECK (true);
CREATE POLICY "Authenticated can update programs" ON public.programs FOR UPDATE TO authenticated USING (true);
CREATE POLICY "Authenticated can delete programs" ON public.programs FOR DELETE TO authenticated USING (true);

CREATE TRIGGER update_programs_updated_at
  BEFORE UPDATE ON public.programs
  FOR EACH ROW
  EXECUTE FUNCTION public.update_updated_at_column();

INSERT INTO public.programs (id, name, description, icon, about, guidelines, sort_order) VALUES
('green-hotel', 'Green Hotel', 'โรงแรมที่เป็นมิตรกับสิ่งแวดล้อม', 'Building2', 'โครงการ Green Hotel มุ่งเน้นการส่งเสริมให้โรงแรมและที่พักดำเนินกิจการอย่างเป็นมิตรกับสิ่งแวดล้อม ครอบคลุมการจัดการพลังงาน น้ำ ขยะ และมลพิษ เพื่อลดผลกระทบต่อสิ่งแวดล้อมและส่งเสริมการท่องเที่ยวอย่างยั่งยืน', '["การจัดการพลังงานอย่างมีประสิทธิภาพ","การจัดการน้ำและน้ำเสีย","การจัดการขยะและของเสีย","การจัดซื้อจัดจ้างที่เป็นมิตรกับสิ่งแวดล้อม","การสร้างความตระหนักรู้ด้านสิ่งแวดล้อม"]', 0),
('green-restaurant', 'Green Restaurant', 'ร้านอาหารที่เป็นมิตรกับสิ่งแวดล้อม', 'UtensilsCrossed', 'โครงการ Green Restaurant ส่งเสริมให้ร้านอาหารมีการจัดการสิ่งแวดล้อมที่ดี ตั้งแต่การเลือกวัตถุดิบ การปรุงอาหาร จนถึงการจัดการขยะอาหาร เพื่อลดผลกระทบต่อสิ่งแวดล้อมจากธุรกิจอาหาร', '["การเลือกใช้วัตถุดิบที่ปลอดภัยและยั่งยืน","การลดการใช้พลาสติกแบบใช้ครั้งเดียว","การจัดการขยะอาหารอย่างมีประสิทธิภาพ","การประหยัดพลังงานในการปรุงอาหาร","การสร้างบรรยากาศที่เป็นมิตรกับสิ่งแวดล้อม"]', 1),
('green-office', 'Green Office', 'สำนักงานสีเขียว', 'Building2', 'โครงการ Green Office มุ่งส่งเสริมให้สำนักงานมีการบริหารจัดการสิ่งแวดล้อมที่ดี เน้นการลดการใช้ทรัพยากร พลังงาน และลดการปล่อยก๊าซเรือนกระจก เพื่อนำไปสู่การเป็นสำนักงานที่เป็นมิตรกับสิ่งแวดล้อมอย่างยั่งยืน', '["นโยบายด้านสิ่งแวดล้อม","การจัดการพลังงานและทรัพยากร","การจัดการของเสียและมลพิษ","สภาพแวดล้อมภายในและภายนอกสำนักงาน","การจัดซื้อจัดจ้างที่เป็นมิตรกับสิ่งแวดล้อม","การปรับปรุงอย่างต่อเนื่อง"]', 2),
('green-residence', 'Green Residence', 'ที่พักอาศัยสีเขียว', 'Home', 'โครงการ Green Residence ส่งเสริมให้ที่พักอาศัย หอพัก และคอนโดมิเนียมมีการจัดการสิ่งแวดล้อมที่ดี มุ่งเน้นความสะอาด ปลอดภัย และเป็นมิตรกับสิ่งแวดล้อม', '["การจัดการพื้นที่สีเขียวภายในที่พัก","การจัดการขยะและการรีไซเคิล","การใช้พลังงานอย่างมีประสิทธิภาพ","การใช้น้ำอย่างประหยัด","การส่งเสริมคุณภาพชีวิตที่ดี"]', 3),
('green-production', 'Green Production', 'การผลิตที่เป็นมิตรกับสิ่งแวดล้อม', 'Factory', 'โครงการ Green Production มุ่งเน้นการส่งเสริมกระบวนการผลิตที่ลดผลกระทบต่อสิ่งแวดล้อม ใช้ทรัพยากรอย่างคุ้มค่า และลดของเสียจากกระบวนการผลิต', '["การออกแบบผลิตภัณฑ์ที่เป็นมิตรกับสิ่งแวดล้อม","การเลือกใช้วัตถุดิบที่ยั่งยืน","การจัดการกระบวนการผลิตที่สะอาด","การจัดการของเสียจากกระบวนการผลิต","การลดการปล่อยมลพิษ"]', 4),
('green-national-park', 'Green National Park', 'อุทยานแห่งชาติสีเขียว', 'Trees', 'โครงการ Green National Park ส่งเสริมการจัดการอุทยานแห่งชาติอย่างยั่งยืน ลดผลกระทบจากการท่องเที่ยว และอนุรักษ์ทรัพยากรธรรมชาติและสิ่งแวดล้อม', '["การจัดการพื้นที่อนุรักษ์อย่างยั่งยืน","การจัดการขยะในพื้นที่อุทยาน","การลดผลกระทบจากกิจกรรมท่องเที่ยว","การอนุรักษ์ทรัพยากรธรรมชาติ","การสร้างจิตสำนึกให้กับนักท่องเที่ยว"]', 5),
('g-upcycle', 'G-Upcycle', 'การนำวัสดุกลับมาใช้ใหม่', 'Recycle', 'โครงการ G-Upcycle ส่งเสริมการนำวัสดุเหลือใช้มาแปรรูปเพิ่มมูลค่า ลดปริมาณขยะ และส่งเสริมเศรษฐกิจหมุนเวียน', '["การคัดแยกวัสดุที่สามารถนำกลับมาใช้ใหม่","การออกแบบและแปรรูปผลิตภัณฑ์จากวัสดุเหลือใช้","การสร้างมูลค่าเพิ่มจากของเหลือใช้","การส่งเสริมเศรษฐกิจหมุนเวียน"]', 6),
('eco-plus', 'Eco Plus', 'มาตรฐานสิ่งแวดล้อมขั้นสูง', 'Award', 'โครงการ Eco Plus เป็นมาตรฐานด้านสิ่งแวดล้อมขั้นสูงสำหรับองค์กรที่มีการจัดการสิ่งแวดล้อมดีเยี่ยม เป็นก้าวต่อไปหลังจากผ่านเกณฑ์ G-Green ระดับพื้นฐาน', '["การบริหารจัดการสิ่งแวดล้อมเชิงรุก","การใช้นวัตกรรมเพื่อสิ่งแวดล้อม","การมีส่วนร่วมของชุมชนและผู้มีส่วนได้ส่วนเสีย","การติดตามและประเมินผลอย่างต่อเนื่อง"]', 7),
('green-hotel-plus', 'Green Hotel Plus', 'โรงแรมที่เป็นมิตรกับสิ่งแวดล้อมอย่างยั่งยืน', 'Star', 'โครงการ Green Hotel Plus เป็นมาตรฐานขั้นสูงสำหรับโรงแรมที่ผ่านเกณฑ์ Green Hotel แล้ว มุ่งเน้นความยั่งยืนในทุกมิติ ทั้งด้านเศรษฐกิจ สังคม และสิ่งแวดล้อม', '["การจัดการพลังงานทดแทน","การลดคาร์บอนฟุตพริ้นท์","การจัดการห่วงโซ่อุปทานที่ยั่งยืน","การรายงานความยั่งยืนอย่างโปร่งใส","การสร้างคุณค่าให้กับชุมชนท้องถิ่น"]', 8),
('g-green-assessment', 'G-Green Assessment Unit', 'หน่วยรับดำเนินงานตรวจประเมิน G-Green', 'ClipboardCheck', 'หน่วยรับดำเนินงานตรวจประเมิน G-Green ทำหน้าที่ตรวจสอบและประเมินผลการดำเนินงานตามเกณฑ์ G-Green ขององค์กรต่าง ๆ เพื่อรับรองมาตรฐานด้านสิ่งแวดล้อม', '["กระบวนการตรวจประเมินตามเกณฑ์มาตรฐาน","การจัดทำรายงานผลการตรวจประเมิน","การติดตามและให้คำแนะนำแก่หน่วยงานที่รับการประเมิน","การพัฒนาศักยภาพผู้ตรวจประเมิน"]', 9);
